  `category` enum('exam','food','transport','supply','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'other',
  `payment_method` enum('cash','pix','credit_card','debit_card','transfer','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'other',
  `description` text COLLATE utf8mb4_unicode_ci,
  `financialable_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `financialable_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `financials_financialable_type_financialable_id_index` (`financialable_type`,`financialable_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
